fn factorial(n: i32) -> Result<i64, String> {
    if n < 0 {
        Err("El factorial no está definido para números negativos".to_string())
    } else if n <= 1 {
        Ok(1)
    } else {
        let prev = factorial(n - 1)?;
        Ok(prev * (n as i64))
    }
}

fn main() {
    println!("5! = {:?}", factorial(5));
    println!("0! = {:?}", factorial(0));
    println!("-3! = {:?}", factorial(-3));
}
