/**
 * Realiza una solicitud GET con reintentos automáticos en caso de fallo.
 * @param {string} url - URL de la API
 * @param {Object} options - Opciones de fetch (headers, body, etc.)
 * @param {number} maxRetries - Número máximo de reintentos (default: 3)
 * @returns {Promise<Response>} - La respuesta exitosa o lanza error
 */
async function fetchWithRetry(url, options = {}, maxRetries = 3) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const response = await fetch(url, options);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return response;
    } catch (error) {
      console.warn(`Intento ${attempt}/${maxRetries} falló:`, error.message);

      if (attempt === maxRetries) {
        throw new Error(`Todos los intentos fallaron: ${error.message}`);
      }

      // Espera exponencial antes de reintentar
      await new Promise(resolve => setTimeout(resolve, attempt * 1000));
    }
  }
}

